"use strict";(self.webpackChunkhosting_capacity_service=self.webpackChunkhosting_capacity_service||[]).push([["1008"],{3094:function(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":"unreleased","badge":true,"noIndex":false,"className":"docs-version-current","isLast":false,"docsSidebars":{"theSidebar":[{"type":"link","label":"Hosting Capacity Service - Home","href":"/evolve/docs/hosting-capacity-service/next/","docId":"home","unlisted":false},{"type":"category","label":"Concepts and Background","items":[{"type":"link","label":"Introduction","href":"/evolve/docs/hosting-capacity-service/next/explanation/explanation-introduction","docId":"explanation/explanation-introduction","unlisted":false},{"type":"link","label":"Hosting Capacity Analysis - How it Works","href":"/evolve/docs/hosting-capacity-service/next/explanation/how-it-works","docId":"explanation/how-it-works","unlisted":false},{"type":"link","label":"What is Network Model Calibration and why is it useful?","href":"/evolve/docs/hosting-capacity-service/next/explanation/calibration-concepts","docId":"explanation/calibration-concepts","unlisted":false},{"type":"link","label":"HCM Scenario Explanation","href":"/evolve/docs/hosting-capacity-service/next/explanation/scenarios","docId":"explanation/scenarios","unlisted":false},{"type":"link","label":"Using HCM Results","href":"/evolve/docs/hosting-capacity-service/next/explanation/using-hcm-results","docId":"explanation/using-hcm-results","unlisted":false},{"type":"link","label":"What are Interventions and why are they useful?","href":"/evolve/docs/hosting-capacity-service/next/explanation/interventions-concepts","docId":"explanation/interventions-concepts","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"How-To Guides","items":[{"type":"link","label":"How to install Python","href":"/evolve/docs/hosting-capacity-service/next/how-to-guides/install-python","docId":"how-to-guides/install-python","unlisted":false},{"type":"link","label":"How to run a work package","href":"/evolve/docs/hosting-capacity-service/next/how-to-guides/run-a-work-package","docId":"how-to-guides/run-a-work-package","unlisted":false},{"type":"link","label":"How to manage work packages","href":"/evolve/docs/hosting-capacity-service/next/how-to-guides/manage-work-packages","docId":"how-to-guides/manage-work-packages","unlisted":false},{"type":"link","label":"How to run Network Model Calibration","href":"/evolve/docs/hosting-capacity-service/next/how-to-guides/calibration","docId":"how-to-guides/calibration","unlisted":false},{"type":"link","label":"How to run Feeder Load Analysis","href":"/evolve/docs/hosting-capacity-service/next/how-to-guides/feeder-load-analysis","docId":"how-to-guides/feeder-load-analysis","unlisted":false},{"type":"link","label":"How to run OpenDSS Exporter","href":"/evolve/docs/hosting-capacity-service/next/how-to-guides/opendss","docId":"how-to-guides/opendss","unlisted":false},{"type":"link","label":"How to set up HCM Scenarios","href":"/evolve/docs/hosting-capacity-service/next/how-to-guides/scenario-how-to","docId":"how-to-guides/scenario-how-to","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Reference","items":[{"type":"link","label":"Input Tables","href":"/evolve/docs/hosting-capacity-service/next/reference/input-tables","docId":"reference/input-tables","unlisted":false},{"type":"link","label":"Output Tables","href":"/evolve/docs/hosting-capacity-service/next/reference/output-tables","docId":"reference/output-tables","unlisted":false},{"type":"link","label":"Work Package Configuration Options","href":"/evolve/docs/hosting-capacity-service/next/reference/configuration","docId":"reference/configuration","unlisted":false},{"type":"link","label":"Configuration Details","href":"/evolve/docs/hosting-capacity-service/next/reference/configuration-details","docId":"reference/configuration-details","unlisted":false},{"type":"link","label":"Model Calibration Methodology","href":"/evolve/docs/hosting-capacity-service/next/reference/calibration-methodology","docId":"reference/calibration-methodology","unlisted":false},{"type":"link","label":"Interventions Options","href":"/evolve/docs/hosting-capacity-service/next/reference/interventions-options","docId":"reference/interventions-options","unlisted":false},{"type":"link","label":"Power Sign Conventions","href":"/evolve/docs/hosting-capacity-service/next/reference/sign-conventions","docId":"reference/sign-conventions","unlisted":false},{"type":"link","label":"Timeseries Data Ingestion","href":"/evolve/docs/hosting-capacity-service/next/reference/timeseries-ingestion","docId":"reference/timeseries-ingestion","unlisted":false},{"type":"link","label":"Load Tables","href":"/evolve/docs/hosting-capacity-service/next/reference/load-tables","docId":"reference/load-tables","unlisted":false},{"type":"link","label":"Node Level Results","href":"/evolve/docs/hosting-capacity-service/next/reference/node-level-results","docId":"reference/node-level-results","unlisted":false},{"type":"link","label":"Closed Loop Voltage Control","href":"/evolve/docs/hosting-capacity-service/next/reference/closed-loop-voltage-control","docId":"reference/closed-loop-voltage-control","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"explanation/calibration-concepts":{"id":"explanation/calibration-concepts","title":"What is Network Model Calibration and why is it useful?","description":"What is Model Calibration?","sidebar":"theSidebar"},"explanation/explanation-introduction":{"id":"explanation/explanation-introduction","title":"Introduction","description":"Energy Workbench Hosting Capacity Module (HCM)","sidebar":"theSidebar"},"explanation/how-it-works":{"id":"explanation/how-it-works","title":"Hosting Capacity Analysis - How it Works","description":"Overview","sidebar":"theSidebar"},"explanation/interventions-concepts":{"id":"explanation/interventions-concepts","title":"What are Interventions and why are they useful?","description":"Once constraints are identified, the HCM allows operators to explore strategies to resolve them through the Intervention Module. This module models changes to both system-wide and local conditions, enabling comparative analysis of mitigation options against the base case. The Intervention Module is a separate module within the Energy Workbench platform, designed to work seamlessly with the HCM. Contact Zepben to enable this module.","sidebar":"theSidebar"},"explanation/scenarios":{"id":"explanation/scenarios","title":"HCM Scenario Explanation","description":"HCM scenarios are named collections of input assumptions that define how distributed energy resources (DER) and demand growth will be distributed across the network in future years.","sidebar":"theSidebar"},"explanation/using-hcm-results":{"id":"explanation/using-hcm-results","title":"Using HCM Results","description":"Overview","sidebar":"theSidebar"},"home":{"id":"home","title":"Hosting Capacity Service - Home","description":"Welcome to the Hosting Capacity Module documentation. This page provides a comprehensive set of resources for how to use the Zepben Hosting Capacity Module (HCM).","sidebar":"theSidebar"},"how-to-guides/calibration":{"id":"how-to-guides/calibration","title":"How to run Network Model Calibration","description":"This page provides a guide for network model calibration within the Hosting Capacity Module. It yields a table of tap settings for each off-load transformer, which can then be used in future work packages to run time-series modelling with the inferred tap positions. It also produces a set of raw results per energy consumer highlighting modelled (simulated) and measured (real) voltages, which can be used to highlight impedance errors in the model and for validation analysis.","sidebar":"theSidebar"},"how-to-guides/feeder-load-analysis":{"id":"how-to-guides/feeder-load-analysis","title":"How to run Feeder Load Analysis","description":"This feature is only available to certain customers and is currently in early release. If you encounter any problems or have questions, please contact Zepben support.","sidebar":"theSidebar"},"how-to-guides/install-python":{"id":"how-to-guides/install-python","title":"How to install Python","description":"How to install python and required libraries","sidebar":"theSidebar"},"how-to-guides/manage-work-packages":{"id":"how-to-guides/manage-work-packages","title":"How to manage work packages","description":"The Work Package Manager is a web UI for browsing, inspecting, and managing work packages submitted to the Hosting Capacity Service.","sidebar":"theSidebar"},"how-to-guides/opendss":{"id":"how-to-guides/opendss","title":"How to run OpenDSS Exporter","description":"This feature is only available to certain customers. If you are interested in using this feature, please contact Zepben for more information.","sidebar":"theSidebar"},"how-to-guides/run-a-work-package":{"id":"how-to-guides/run-a-work-package","title":"How to run a work package","description":"This section provides guidance on how to interact with the Hosting Capacity Service by using our Python library.","sidebar":"theSidebar"},"how-to-guides/scenario-how-to":{"id":"how-to-guides/scenario-how-to","title":"How to set up HCM Scenarios","description":"This guide walks you through the process of configuring HCM scenarios, from preparing the required data tables to creating scenario configurations that can be executed in work packages.","sidebar":"theSidebar"},"how-to-guides/validation-scripts":{"id":"how-to-guides/validation-scripts","title":"Validation Scripts","description":"Data validation scripts are provided as-is without formal support. They are intended to test data validation as we develop more formal data validation tools."},"reference/calibration-methodology":{"id":"reference/calibration-methodology","title":"Model Calibration Methodology","description":"This page provides a detailed overview of the methodology used for network Model Calibration within the Hosting Capacity Module. It yields a table of tap settings for each off-load transformer, which can then be used in future work packages to run time-series modelling with the inferred tap positions. It also produces a set of results per Energy Consumer allowing the comparison between modelled (simulated) and measured (real) voltages, which can be used to validate the model and understand the uncertainty in the model.","sidebar":"theSidebar"},"reference/closed-loop-voltage-control":{"id":"reference/closed-loop-voltage-control","title":"Closed Loop Voltage Control","description":"Closed Loop Voltage Control (CLVC) is the algorithm used to model how zone substations regulate voltage in response to load and generation changes. The CLVC settings affect voltage levels across the network and therefore influence both overvoltage constraint results (generation-driven) and undervoltage constraint results (load-driven).","sidebar":"theSidebar"},"reference/configuration":{"id":"reference/configuration","title":"Work Package Configuration Options","description":"There are various elements that must be configured to successfully create an OpenDSS model from the input data, which are then used to run a Hosting Capacity Model work package.","sidebar":"theSidebar"},"reference/configuration-details":{"id":"reference/configuration-details","title":"Configuration Details","description":"This page contains information on certain configuration elements that require more explanation or discussion than the regular Work Package Configuration Options page provides.","sidebar":"theSidebar"},"reference/input-tables":{"id":"reference/input-tables","title":"Input Tables","description":"HCM Scenario Definition Tables","sidebar":"theSidebar"},"reference/interventions-options":{"id":"reference/interventions-options","title":"Interventions Options","description":"This feature is only available to certain customers. If you are interested in using this feature, please contact Zepben for more information.","sidebar":"theSidebar"},"reference/load-tables":{"id":"reference/load-tables","title":"Load Tables","description":"The load database stores smart meter data, power quality readings, and feeder-level measurements used by the Hosting Capacity Module (HCM) and related services. It runs on PostgreSQL with the TimescaleDB extension.","sidebar":"theSidebar"},"reference/node-level-results":{"id":"reference/node-level-results","title":"Node Level Results","description":"This feature is in active development and is only available to select customers. If you are interested in using this feature, please contact Zepben for more information.","sidebar":"theSidebar"},"reference/output-tables":{"id":"reference/output-tables","title":"Output Tables","description":"This is a list of all the output tables available in the Hosting Capacity Service database, along with detailed descriptions of each column and how to use them. Note that depending on the specific implementation, your tables may not be located in an \'output\' database, but may be found alongside input tables in an \'input/results\' database. Contact Zepben support if you are unsure.","sidebar":"theSidebar"},"reference/sign-conventions":{"id":"reference/sign-conventions","title":"Power Sign Conventions","description":"This section defines exactly how the Hosting Capacity Module (HCM) interprets signs for active power (P), reactive power (Q), and power factor (PF) across three key areas:","sidebar":"theSidebar"},"reference/timeseries-ingestion":{"id":"reference/timeseries-ingestion","title":"Timeseries Data Ingestion","description":"This section describes the file formats and requirements for ingesting customer meter reading data (AMI/NMI data) into the Zepben timeseries database for use in Hosting Capacity Module work packages.","sidebar":"theSidebar"},"tutorials/output-tutorial":{"id":"tutorials/output-tutorial","title":"Output Tutorial","description":"\'Using Python to understand the HCM Outputs\' tutorial will go here soon, once we have a sample database ready."}}}}')}}]);